+    const border: u32 = 2; // 2px black border
+
+    // Draw black border first (fill entire badge area)
+    var py: u32 = 0;
+    while (py < h and y + py < height) : (py += 1) {
+        var px: u32 = 0;
+        while (px < w and x + px < stride) : (px += 1) {
+            const idx = ((y + py) * stride + (x + px)) * 4;
+            if (idx + 3 >= buf.len) continue;
+            buf[idx] = 0; // R
